126→// flattenMocks extracts the first MockConfig slice from the variadic parameter.
127→func flattenMocks(mocks [][]MockConfig) []MockConfig {
128→	if len(mocks) > 0 && len(mocks[0]) > 0 {
129→		return mocks[0]
130→	}
131→	return nil
132→}
