162→func (h *Handler) handleAnalyze(resp Response, req Request) Response {
163→	if req.File == "" {
164→		resp.Status = "error"
165→		resp.Code = ErrInvalidRequest
166→		resp.Message = "analyze command requires a file path"
167→		return resp
168→	}
169→
170→	if _, err := os.Stat(req.File); err != nil {
171→		resp.Status = "error"
172→		resp.Code = ErrFileNotFound
173→		resp.Message = fmt.Sprintf("file not found: %s", req.File)
174→		return resp
175→	}
176→
177→	h.lastAnalyzedFile = req.File
178→
179→	var functionName string
180→	if req.Function != nil {
181→		functionName = *req.Function
182→	}
183→
184→	functions, err := AnalyzeFile(req.File, functionName)
185→	if err != nil {
186→		if functionName != "" && isNotFound(err) {
187→			resp.Status = "error"
188→			resp.Code = ErrFunctionNotFound
189→			resp.Message = fmt.Sprintf("function %q not found in %s", functionName, req.File)
190→			return resp
191→		}
192→		resp.Status = "error"
193→		resp.Code = ErrParseError
194→		resp.Message = err.Error()
195→		return resp
196→	}
197→
198→	resp.Status = "analyze"
199→	if functions == nil {
200→		functions = []FunctionAnalysis{}
201→	}
202→	resp.Functions = functions
203→	return resp
204→}
205→
206→func isNotFound(err error) bool {
207→	return err != nil && strings.HasPrefix(err.Error(), "function not found")
208→}
