550→// parseMajorMinor extracts the major and minor components from a semver string.
551→// Returns (major, minor, ok). ok is false if the version string is malformed.
552→func parseMajorMinor(version string) (int, int, bool) {
553→	parts := strings.SplitN(version, ".", 3)
554→	if len(parts) < 2 {
555→		return 0, 0, false
556→	}
557→	major, err := strconv.Atoi(parts[0])
558→	if err != nil {
559→		return 0, 0, false
560→	}
561→	minor, err := strconv.Atoi(parts[1])
562→	if err != nil {
563→		return 0, 0, false
564→	}
565→	return major, minor, true
566→}
567→
568→// isVersionCompatible checks whether a requested protocol version is compatible
569→// with ProtocolVersion by comparing major and minor components (patch is ignored).
570→// Matches the TypeScript frontend's semver-compatible behavior.
571→func isVersionCompatible(version string) bool {
572→	reqMajor, reqMinor, reqOK := parseMajorMinor(version)
573→	ourMajor, ourMinor, ourOK := parseMajorMinor(ProtocolVersion)
574→	if !reqOK || !ourOK {
575→		return false
576→	}
577→	return reqMajor == ourMajor && reqMinor == ourMinor
578→}
