580→func (h *Handler) send(resp Response) error {
581→	data, err := json.Marshal(resp)
582→	if err != nil {
583→		return fmt.Errorf("marshaling response: %w", err)
584→	}
585→	line := string(data) + "\n"
586→	h.log.Log(context.Background(), LevelTrace, "Sent", "raw", string(data))
587→	_, err = io.WriteString(h.writer, line)
588→	return err
589→}
