 24→func genTypeInfoLeaf() *rapid.Generator[TypeInfo] {
 25→	return rapid.Map(
 26→		rapid.SampledFrom([]string{"int", "float", "str", "bool", "unknown"}),
 27→		func(kind string) TypeInfo { return TypeInfo{Kind: kind} },
 28→	)
 29→}
