 31→func genTypeInfo(depth int) *rapid.Generator[TypeInfo] {
 32→	if depth <= 0 {
 33→		return genTypeInfoLeaf()
 34→	}
 35→	return rapid.OneOf(
 36→		genTypeInfoLeaf(),
 37→		rapid.Map(genTypeInfo(depth-1), func(elem TypeInfo) TypeInfo {
 38→			return TypeInfo{Kind: "array", Element: &elem}
 39→		}),
 40→		rapid.Map(genTypeInfo(depth-1), func(inner TypeInfo) TypeInfo {
 41→			return TypeInfo{Kind: "nullable", Inner: &inner}
 42→		}),
 43→		rapid.Map(
 44→			rapid.SliceOfN(genTypeInfo(depth-1), 2, 3),
 45→			func(variants []TypeInfo) TypeInfo {
 46→				return TypeInfo{Kind: "union", Variants: variants}
 47→			},
 48→		),
 49→		rapid.Custom[TypeInfo](func(t *rapid.T) TypeInfo {
 50→			return TypeInfo{Kind: "opaque", Label: genIdent().Draw(t, "label")}
 51→		}),
 52→	)
 53→}
